// Helper: generate a plausible interest time series
function _makeSeries(days, baseVal, peak, peakDay) {
  const out = [];
  const now = new Date('2026-04-28');
  for (let i = days; i >= 0; i--) {
    const d = new Date(now);
    d.setDate(d.getDate() - i);
    const iso = d.toISOString().slice(0, 10);
    // Simple sine + noise pattern
    const dist = Math.abs(i - peakDay);
    const wave = Math.sin((i / days) * Math.PI * 3) * 10;
    const spike = Math.max(0, (peak - baseVal) * Math.exp(-dist * dist / 80));
    const noise = (Math.random() - 0.5) * 8;
    const val = Math.min(100, Math.max(5, Math.round(baseVal + wave + spike + noise)));
    out.push({ date: iso, value: val });
  }
  return out;
}

