// Summary table data derived from GTRENDS_DATA
function getGtrendsSummary() {
  return GTRENDS_MARKETS.map(market => {
    const mdata = GTRENDS_DATA[market];
    return {
      market,
      geo: mdata.geo,
      blocked: !!(mdata['90d'] && mdata['90d'].blocked),
      avg90d: mdata['90d']?.avgInterest,
      peak90d: mdata['90d']?.peakInterest,
      rising90d: (mdata['90d']?.risingQueries || []).length,
      breakout90d: (mdata['90d']?.risingQueries || []).filter(q => q.type === 'breakout').length,
      avg30d: mdata['30d']?.avgInterest,
      peak30d: mdata['30d']?.peakInterest,
      rising30d: (mdata['30d']?.risingQueries || []).length,
      breakout30d: (mdata['30d']?.risingQueries || []).filter(q => q.type === 'breakout').length,
    };
  });
}
